#define HEALTH 100
#define PLAYER_SPEED 2
#define PLAYER_HITBOX_OFFSET_X 7
#define PLAYER_HITBOX_OFFSET_Y 8
#define PLAYER_HITBOX_W 13
#define PLAYER_HITBOX_H 18
#define PLAYER_W SOLDIER_W
#define PLAYER_H SOLDIER_H

#define ATTACK_1_DAMAGE 10
#define ATK1_COOLDOWN 20

#define ATTACK_2_DAMAGE 18
#define ATK2_COOLDOWN 30

#define PROJECTILE_DAMAGE 12
#define SHOOT_COOLDOWN 45

#define DASH_COOLDOWN 60
#define DASH_TIMER 15

#define BLOCK_COOLDOWN 30
#define BLOCK_TIMER 15

/* #include "entity.h" -- merged */
/* #include "sprite.h" -- merged */
/* #include "player_config.h" -- merged */

void player_init(Entity *p, SpriteID sprite, short _colour, const PlayerConfig *cfg, int x_start, int flip);
void player_update(Entity *p, int cur_buf);
void player_draw(const Entity *p);


/* ===========================================================================
 * src/game/player.c
 * =========================================================================*/
/* #include "player.h" -- merged */
/* #include "vga.h" -- merged */
/* #include "keyboard.h" -- merged */
/* #include "animator.h" -- merged */
/* #include "renderer.h" -- merged */
/* #include "map.h" -- merged */

void player_init(Entity *p, SpriteID sprite, short _colour, const PlayerConfig *cfg, int start_x, int flip){
    p->player_cfg = cfg; //not needed at init
    p->x = start_x;
    p->y = SCREEN_HEIGHT / 2 - PLAYER_H / 2;

    p->width = PLAYER_W;
    p->height = PLAYER_H;

    p->dx = 0;
    p->dy = 0;

    p->health = HEALTH;

    p->facing = flip ? 'w' : 'e';  //n for north (up), s for south(dowm), e for east(right), w for west (left)

    p->hitbox_x = p->x + PLAYER_HITBOX_OFFSET_X;
    p->hitbox_y = p->y + PLAYER_HITBOX_OFFSET_Y;

    p->hitbox_w = PLAYER_HITBOX_W;
    p->hitbox_h = PLAYER_HITBOX_H;

    p->sprite_id = (int)sprite;
    p->colour = _colour; //white

    p->type = ENTITY_PLAYER;
    p->active = 1;
    p->dying = 0;
    
    p->anim_def = SOLDIER_ANIMS;

    anim_init(&p->anim, p->anim_def, SOLIDER_IDLE);
    p->anim.flip = flip;
   
    p->prev_x[0] = p->x;
    p->prev_x[1] = p->x;
    p->prev_y[0] = p->y;
    p->prev_y[1] = p->y;

    p->attack_s1 = 0;
    p->attack_s2 = 0;
    p->attack_p = 0;

    p->was_hit = 0;
    p->damage = 0;

    p->pending_erase = 0;
    p->shoot_cooldown = 0;
    p->arrow_fired = 0;

    p->atk1_cooldown = 0;
    p->atk2_cooldown = 0;

    p->dash_cooldown = 0;
    p->dash_timer = 0;
    p->is_dashing = 0;

    p->block_cooldown = 0;
    p->block_timer = 0;
    p->blocking = 0;
}

void player_update(Entity *p, int cur_buf){
    /*Save postion before returning so erase works*/
        p->prev_x[cur_buf] = p->x;
        p->prev_y[cur_buf] = p->y;
    
    /* 1. Tick animation first - returns 1 when one shot is done*/
    int anim_finished = anim_tick(&p->anim, p->anim_def);
    
    /* 2. If currently play death animation, wait for it to finish*/
    if (p->dying){
        if(anim_finished){
            p->active = 0; /*deactive after death anim*/
        }
        return;
    }

    /* 3. Handle incoming hit */
    if(p->was_hit){
        p->was_hit = 0;
        p->health -= p->damage;
        p->damage = 0;

        if(p->health < 0){
            p->health = 0;
            p->dying = 1;
            anim_play(&p->anim, p->anim_def, SOLDIER_DEATH);
        }
        else{
            anim_play(&p->anim, p->anim_def, SOLDIER_HURT);
        }
        return;
    }

    /* 4. Locked if you shouldnt be able to move during the animation*/
    int locked = (p->anim.anim == SOLDIER_ATK1 ||
                  p->anim.anim == SOLDIER_ATK2 ||
                  //p->anim.anim == SOLDIER_ATK3 ||
                  p->anim.anim == SOLDIER_HURT  ||
                  p->anim.anim == SOLDIER_DEATH);

    /* Advance animation â€” returns 1 if one-shot just ended */
    if (anim_finished) {
        p->attack_s1 = 0;
        p->attack_s2 = 0;
        anim_play(&p->anim, p->anim_def, SOLIDER_IDLE);
        locked = 0;
    }

    /*decect release frame for arrow*/
    if (p->anim.anim == SOLDIER_ATK3 && p->anim.frame == SOLDIER_ANIMS[SOLDIER_ATK3].end - 1 && !p->attack_p && !p->arrow_fired){
        p->attack_p = 1;
        p->arrow_fired = 1;
    }

    if (locked) return;

    /* Handle cooldowns*/
    if(p->atk1_cooldown > 0){
        p->atk1_cooldown--;
    }

    if(p->atk2_cooldown > 0){
        p->atk2_cooldown--;
    }

    if(p->shoot_cooldown > 0){
        p->shoot_cooldown--;
    }

    if(p->dash_cooldown > 0 && !p->is_dashing){
        p->dash_cooldown--;
    }

    if(p->block_cooldown > 0 && !p->blocking){
        p->block_cooldown--;
    }

    /* Attack input (takes priority over movement) */
    const PlayerConfig *cfg = p->player_cfg;
    if (key_pressed(cfg->key_atk1) && p->atk1_cooldown == 0) {
        anim_play(&p->anim, p->anim_def, SOLDIER_ATK1);
        p->atk1_cooldown = ATK1_COOLDOWN;
        p->attack_s1 = 1;
        return;
    }
    if (key_pressed(cfg->key_atk2) && p->atk2_cooldown == 0) {
        anim_play(&p->anim, p->anim_def, SOLDIER_ATK2);
        p->atk2_cooldown = ATK2_COOLDOWN;
        p->attack_s2 = 1;
        return;
    }

    if (key_pressed(cfg->key_atkp) && p->shoot_cooldown == 0){
        anim_play(&p->anim, p->anim_def, SOLDIER_ATK3);
        p->shoot_cooldown = SHOOT_COOLDOWN;
        p->arrow_fired = 0;
        return;
    }

    if(key_pressed(cfg->key_dash) && p->dash_cooldown == 0){
        p->dash_cooldown = DASH_COOLDOWN;
        p->is_dashing = 1;
        p->dash_timer = DASH_TIMER;
    }

    if(key_pressed(cfg->key_block) && p->block_cooldown == 0){
        p->block_cooldown = BLOCK_COOLDOWN;
        p->blocking = 1;
        p->block_timer = BLOCK_TIMER;
    }

    /* Movement */
    if(!p->is_dashing){
        p->dx = 0;
        p->dy = 0;
    }

    if (!p->is_dashing && key_pressed(p->player_cfg->key_up)) {
        p->dy = -PLAYER_SPEED;
       // p->facing = 'n';
    }
    if(!p->is_dashing && key_pressed(p->player_cfg->key_down)){
        p->dy = PLAYER_SPEED;
      //  p->facing = 's';
    }
    if (!p->is_dashing && key_pressed(p->player_cfg->key_left))  { 
        p->dx = -PLAYER_SPEED;
        p->facing = 'w'; 
        p->anim.flip = 1;
    }
    if (!p->is_dashing && key_pressed(p->player_cfg->key_right)) { 
        p->dx =  PLAYER_SPEED; 
        p->facing = 'e'; 
        p->anim.flip = 0;
    }

    //half player movement while bow is drawn
    if(p->anim.anim == SOLDIER_ATK3 && !p->arrow_fired){
        p->dx = p->dx >> 1;
        p->dy = p->dy >> 1;
    }
    if(p->anim.anim == SOLDIER_ATK3 && p->arrow_fired){
        p->dx = p->dx << 1;
        p->dy = p->dy << 1;
    }

    if(p->is_dashing && p->dash_timer == DASH_TIMER){
        p->dx = p->dx << 1;
        p->dy = p->dy << 1;
    }
    if(p->is_dashing){
        p->dash_timer--;
        if(p->dash_timer == 0){
            p->is_dashing = 0;
            p->dx = p->dx >> 1;
            p->dy = p->dy >> 1;
        }
    }

    if(p->blocking){
        p->dx = p->dx >> 1;
        p->dy = p->dy >> 1;
        p->block_timer--;
    }
    if(p->blocking && p->block_timer == 0){
        p->dx = p->dx << 1;
        p->dy = p->dy << 1;
        p->blocking = 0;
    }

    //Check if we should play idle animation
    
    if(p->anim.anim != SOLDIER_ATK3){
        int moving = (p->dx != 0 || p->dy != 0);
        anim_play(&p->anim, p->anim_def, moving ? SOLDIER_WALK : SOLIDER_IDLE);
    }

    p->x += p->dx;
    p->y += p->dy;

    /*Now clamp*/
    if (p->x  < 0){
        p->x = 0;
    }                       
    if (p->y < 0){
        p->y = 0;
    }

    if(p->x + p->width > SCREEN_WIDTH)
        p->x = SCREEN_WIDTH - p->width;

    if(p->y + p->height > SCREEN_HEIGHT)
        p->y = SCREEN_HEIGHT - p->height;

    
    /* Update hitbox to follow player postion */
    if(p->facing == 'e'){
        p->hitbox_x = p->x + PLAYER_HITBOX_OFFSET_X;
    }
    
    if(p->facing == 'w'){
        p->hitbox_x = p->x + SOLDIER_W - PLAYER_HITBOX_OFFSET_X - p->hitbox_w;
    }
    p->hitbox_y = p->y + PLAYER_HITBOX_OFFSET_Y;
}

void player_draw(const Entity *p){
    draw_soldier(&p->anim, p->x, p->y);
    if(p->blocking){
        int flip_h = 0;
        int x_off = 0;
        if(p->facing == 'w'){
            flip_h = 1;
            int x_off = -1;
        }
        draw_sprite(&sprites[SPRITE_WOOD_SHIELD], p->hitbox_x + x_off, p->hitbox_y + 2, flip_h, 0);
    }
    draw_rect_outline(p->hitbox_x, p->hitbox_y, p->hitbox_w, p->hitbox_h, 0x0000);
}


